// This is the code for your Firebase Cloud Functions.
// To make this function work, you MUST deploy it to your Firebase project.
//
// HOW TO DEPLOY:
// 1. Setup Firebase CLI: If you haven't, install it on your computer: `npm install -g firebase-tools` 
// 2. Login: Run `firebase login` in your terminal.
// 3. Initialize Firebase in your project root: Run `firebase init functions`.
//    - Select your "trustora2" project.
//    - Choose TypeScript as the language.
//    - Say yes to install dependencies.
// 4. Copy this code: Replace the content of `functions/src/index.ts` in your project with this code.
// 5. Deploy: Run `firebase deploy --only functions` from your project's root directory in the terminal.
// 
// Once deployed, this function will automatically run every time a user's data is created, updated, or deleted. 
//
// NOTE: This function recalculates the total supply on every change. 
// This is inefficient for large numbers of users. For production, consider
// using an incremental update strategy instead to avoid potential cost implications.


// Fix: Use v2 import for Firestore triggers to align with firebase-functions v2 SDK.
import { onDocumentWritten } from "firebase-functions/v2/firestore";
import * as admin from "firebase-admin";

// Initialize the Firebase Admin SDK to access Firestore. 
admin.initializeApp();

const db = admin.firestore();

/**
 * Cloud Function to update the total circulating TSR supply in real-time.
 *
 * This function triggers on any write to a user document and recalculates
 * the entire supply by summing the `tsrBalance` from all user documents.
 * This approach ensures the total is always accurate and accounts for
 * data that existed before the function was deployed.
 */
// Fix: Use Firebase Functions v2 syntax to resolve 'document' property error.
export const updateCirculatingTsrSupply = onDocumentWritten("users/{userId}", async (event) => {
    // A reference to the users collection.
    const usersRef = db.collection("users");

    // Get all documents from the 'users' collection.
    const allUsersSnapshot = await usersRef.get();

    let newTotalTsr = 0;

    // Iterate over each user document to calculate the sum.
    allUsersSnapshot.forEach(doc => {
      const userData = doc.data();
      // Ensure the field name 'tsrBalance' matches your Firestore document exactly.
      const balance = userData.tsrBalance;

      // Ensure the balance is a valid, positive number before adding it.
       // This prevents issues with missing fields or negative values.
      if (typeof balance === 'number' && balance > 0) {
        newTotalTsr += balance;
      }
    });

    console.log(`Recalculated total TSR supply: ${newTotalTsr}`);

    // The central document where the total supply is stored.
    const supplyDocRef = db.doc("app_settings/circulatingSupply");

    try {
      // Save the newly calculated total to Firestore.
      // The `{ merge: true }` option prevents overwriting other potential
      // fields in the document and creates the document if it doesn't exist.
      await supplyDocRef.set(
        {
          // Ensure the field name 'totalTsr' matches what your app is listening for.
          totalTsr: newTotalTsr,
        },
        { merge: true }
       );
      console.log(`Successfully set totalTsr supply to ${newTotalTsr}.`);
      return null;
    } catch (error) {
      console.error(
        "Failed to update circulating TSR supply. Error:",
        error
      );
      return null;
    }
  });
